script:
const { point, session, context, axios, notification, overlay } = scope;

const lon = point.coordinates[0];
const lat = point.coordinates[1];
const parkingGroup = session.groups.find(g => g.name === 'Filming Activity');
const points = session.points[parkingGroup.id].filter(p => Math.abs(p.coordinates[0] - lon) < 0.003 && Math.abs(p.coordinates[1] - lat) < 0.003);

overlay({
  message: `Found Filming Activity Near The Parking Space:
	${points.map(p => p.properties[2] + ' - ' + p.properties[0]).join(', \n')}.
  `,
});
